1	import { useEffect, useState } from 'react';
2	import {
3	  type LayoutChangeEvent,
4	  type StyleProp,
5	  StyleSheet,
6	  View,
7	  type ViewStyle,
8	} from 'react-native';
9	import Animated, {
10	  cancelAnimation,
11	  Easing,
12	  useAnimatedStyle,
13	  useSharedValue,
14	  withRepeat,
15	  withTiming,
16	} from 'react-native-reanimated';
17	import { colors, radii, shadows } from '@/design/tokens';
18	import { useReducedMotion } from '@/design/useReducedMotion';
19	
20	export type SkeletonCardShape = 'card' | 'line';
21	
22	export type SkeletonCardProps = {
23	  height?: number;
24	  shape?: SkeletonCardShape;
25	  style?: StyleProp<ViewStyle>;
26	  testID?: string;
27	};
28	
29	// Loading placeholder per docs/design.md §5.1 ("Loading (3 skeleton cards)") +
30	// §6 inventory. Shimmer is a translated surface-colored band animated across the
31	// skeleton's width on a repeating worklet. Reduced-motion short-circuits: the
32	// placeholder renders with its neutral hairline bg and no moving band.
33	export function SkeletonCard({
34	  height = 140,
35	  shape = 'card',
36	  style,
37	  testID,
38	}: SkeletonCardProps) {
39	  const reduced = useReducedMotion();
40	  const progress = useSharedValue(0);
41	  const [width, setWidth] = useState(0);
42	
43	  useEffect(() => {
44	    if (reduced || width === 0) return;
45	    progress.value = 0;
46	    progress.value = withRepeat(
47	      withTiming(1, { duration: 1200, easing: Easing.inOut(Easing.quad) }),
48	      -1,
49	      false,
50	    );
51	    return () => {
52	      cancelAnimation(progress);
53	    };
54	  }, [reduced, width, progress]);
55	
56	  const bandWidth = Math.max(80, width * 0.4);
57	
58	  const animatedStyle = useAnimatedStyle(() => {
59	    const start = -bandWidth;
60	    const end = width;
61	    return {
62	      transform: [{ translateX: start + (end - start) * progress.value }],
63	    };
64	  });
65	
66	  const handleLayout = (event: LayoutChangeEvent) => {
67	    const w = event.nativeEvent.layout.width;
68	    if (w !== width) setWidth(w);
69	  };
70	
71	  const outerStyle =
72	    shape === 'card' ? [styles.card, shadows.hard, { height }] : [styles.line, { height }];
73	
74	  return (
75	    <View
76	      style={[outerStyle, style]}
77	      onLayout={handleLayout}
78	      testID={testID}
79	      accessible
80	      accessibilityLabel="Loading"
81	      accessibilityState={{ busy: true }}
82	    >
83	      {!reduced && width > 0 ? (
84	        <Animated.View
85	          pointerEvents="none"
86	          style={[styles.shimmer, { width: bandWidth }, animatedStyle]}
87	        />
88	      ) : null}
89	    </View>
90	  );
91	}
92	
93	const styles = StyleSheet.create({
94	  card: {
95	    backgroundColor: colors.hairline,
96	    borderRadius: radii.card,
97	    borderWidth: 2,
98	    borderColor: colors.ink,
99	    overflow: 'hidden',
100	  },
101	  line: {
102	    backgroundColor: colors.hairline,
103	    borderRadius: radii.image,
104	    overflow: 'hidden',
105	  },
106	  shimmer: {
107	    position: 'absolute',
108	    top: 0,
109	    bottom: 0,
110	    backgroundColor: colors.surface,
111	    opacity: 0.6,
112	  },
113	});
